theme.custom_css_code:
.ivy-brand-table-wrap {
  width: 100%;
  background: transparent;
  font-family: Arial, sans-serif;
}

.ivy-brand-table-scroll {
  width: 100%;
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  border-radius: 18px;
  background: rgba(255, 255, 255, 0.04);
  box-shadow: 0 10px 30px rgba(0, 0, 0, 0.22);
}

.ivy-brand-table {
  width: 100%;
  min-width: 680px;
  border-collapse: collapse;
  color: #f5eef4;
  background: transparent;
}

.ivy-brand-table td {
  padding: 14px 16px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.09);
  vertical-align: top;
  font-size: 15px;
  line-height: 1.45;
}

.ivy-brand-table tr:last-child td {
  border-bottom: none;
}

.ivy-brand-table td:first-child {
  width: 32%;
  font-weight: 700;
  color: #ffffff;
  background: rgba(255, 255, 255, 0.03);
}

.ivy-brand-table td:last-child {
  width: 68%;
  color: #ddd4dd;
}

@media (max-width: 767px) {
  .ivy-brand-table td {
    padding: 12px 13px;
    font-size: 14px;
  }
}
.ivy-games-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 16px;
  width: 100%;
  background: transparent;
  font-family: Arial, sans-serif;
}

.ivy-game-card {
  position: relative;
  padding: 22px 18px 18px;
  border-radius: 22px;
  overflow: hidden;
  background: linear-gradient(160deg, rgba(255,255,255,0.08), rgba(255,255,255,0.03));
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.24);
  border: 1px solid rgba(255,255,255,0.08);
  min-height: 190px;
}

.ivy-game-card::before {
  content: "";
  position: absolute;
  inset: 0;
  background:
    radial-gradient(circle at top right, rgba(255,255,255,0.12), transparent 42%),
    radial-gradient(circle at bottom left, rgba(255,255,255,0.06), transparent 38%);
  pointer-events: none;
}

.ivy-game-icon {
  position: relative;
  z-index: 1;
  width: 54px;
  height: 54px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 16px;
  font-size: 28px;
  background: rgba(255,255,255,0.1);
  margin-bottom: 16px;
}

.ivy-game-name {
  position: relative;
  z-index: 1;
  color: #ffffff;
  font-size: 20px;
  line-height: 1.2;
  font-weight: 700;
  margin-bottom: 10px;
}

.ivy-game-text {
  position: relative;
  z-index: 1;
  color: #ddd6dd;
  font-size: 14px;
  line-height: 1.55;
}

.ivy-game-card-slots { background: linear-gradient(160deg, rgba(111,84,120,0.38), rgba(255,255,255,0.03)); }
.ivy-game-card-megaways { background: linear-gradient(160deg, rgba(101,85,135,0.34), rgba(255,255,255,0.03)); }
.ivy-game-card-live { background: linear-gradient(160deg, rgba(61,92,112,0.34), rgba(255,255,255,0.03)); }
.ivy-game-card-blackjack { background: linear-gradient(160deg, rgba(74,114,92,0.32), rgba(255,255,255,0.03)); }
.ivy-game-card-roulette { background: linear-gradient(160deg, rgba(126,76,90,0.33), rgba(255,255,255,0.03)); }
.ivy-game-card-promos { background: linear-gradient(160deg, rgba(135,102,67,0.34), rgba(255,255,255,0.03)); }

.ivy-games-card-sep {
  display: none;
}

@media (max-width: 991px) {
  .ivy-games-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 640px) {
  .ivy-games-grid {
    grid-template-columns: 1fr;
    gap: 14px;
  }

  .ivy-game-card {
    min-height: auto;
    padding: 18px 16px 16px;
    border-radius: 18px;
  }

  .ivy-game-icon {
    width: 48px;
    height: 48px;
    font-size: 24px;
    margin-bottom: 14px;
  }

  .ivy-game-name {
    font-size: 18px;
  }

  .ivy-game-text {
    font-size: 13px;
  }
}
.ivy-ux-chart {
  width: 100%;
  background: transparent;
  font-family: Arial, sans-serif;
  padding: 8px 0;
}

.ivy-ux-bar {
  margin-bottom: 16px;
}

.ivy-ux-bar:last-child {
  margin-bottom: 0;
}

.ivy-ux-bar-label {
  color: #f7f2f6;
  font-size: 15px;
  font-weight: 700;
  margin-bottom: 8px;
}

.ivy-ux-bar-track {
  width: 100%;
  height: 18px;
  border-radius: 999px;
  background: rgba(255,255,255,0.08);
  overflow: hidden;
  box-shadow: inset 0 0 0 1px rgba(255,255,255,0.05);
}

.ivy-ux-bar-fill {
  height: 100%;
  border-radius: 999px;
  display: flex;
  align-items: center;
  justify-content: flex-end;
  padding-right: 8px;
  color: #ffffff;
  font-size: 11px;
  font-weight: 700;
  white-space: nowrap;
  box-sizing: border-box;
}

.ivy-ux-bar-fill span {
  position: relative;
  top: -0.5px;
}

.ivy-ux-bar-fill-slots {
  width: 92%;
  background: linear-gradient(90deg, #9f79a9, #e7c7ef);
}

.ivy-ux-bar-fill-payments {
  width: 86%;
  background: linear-gradient(90deg, #7b8fc1, #bcd3ff);
}

.ivy-ux-bar-fill-mobile {
  width: 84%;
  background: linear-gradient(90deg, #6a9ca7, #a8e0ea);
}

.ivy-ux-bar-fill-live {
  width: 71%;
  background: linear-gradient(90deg, #6f8b74, #b8d7be);
}

.ivy-ux-bar-fill-beginner {
  width: 58%;
  background: linear-gradient(90deg, #8e6e76, #d6b0ba);
}

.ivy-ux-bar-fill-bonus {
  width: 62%;
  background: linear-gradient(90deg, #977956, #e2c193);
}

@media (max-width: 640px) {
  .ivy-ux-bar {
    margin-bottom: 14px;
  }

  .ivy-ux-bar-label {
    font-size: 14px;
    margin-bottom: 7px;
  }

  .ivy-ux-bar-track {
    height: 16px;
  }

  .ivy-ux-bar-fill {
    font-size: 10px;
    padding-right: 6px;
  }
}
